    const indicesOfOne = [];
    const indicesOfTwo = [];

    // Collect indices of 1s and 2s
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            indicesOfOne.push(i);
        } else if (nums[i] === 2) {
            indicesOfTwo.push(i);
        }
    }

    // If either list is empty, no valid pair exists
