    // Given N <= 100, N1*N2 <= 10000, which is very fast.
    for (const i of indicesOfOne) {
        for (const j of indicesOfTwo) {
            const diff = Math.abs(i - j);
            if (diff < minDiff) {
                minDiff = diff;
            }
        }
    }

    return minDiff;
}

